scripts.questions:
const questions = flowData.intents.payload.questions;
let currentQuestionId = questions[0].id;

function findQuestionById(id) {
    return questions.find(q => q.id === id);
}

function showQuestion(question) {
    // Display question label
    showBotResponse(question.label, (question.options || []).map(opt => opt.value), question.links);

    // If options, render buttons; else, wait for user input
}

function handleOptionClick(optionValue) {
    const question = findQuestionById(currentQuestionId);
    const selected = (question.options || []).find(opt => opt.value === optionValue);
    if (selected && selected.next && selected.next.target) {
        currentQuestionId = selected.next.target;
        showQuestion(findQuestionById(currentQuestionId));
    }
}

function handleUserInput(userMessage) {
    const question = findQuestionById(currentQuestionId);
    if (question.next && question.next.target) {
        currentQuestionId = question.next.target;
        showQuestion(findQuestionById(currentQuestionId));
    }
}

// On page load
showQuestion(findQuestionById(currentQuestionId));
